create extension if not exists pgcrypto;
create type public.app_role as enum ('user','admin');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text not null default '',avatar_path text,created_at timestamptz not null default now());
create table public.user_roles(user_id uuid not null references auth.users(id) on delete cascade,role public.app_role not null default 'user',primary key(user_id,role));
create table public.activities(id bigint generated by default as identity primary key,title text not null,category text not null,minutes int not null check(minutes>0),level text not null default 'Easy',icon text,created_at timestamptz not null default now());
create table public.activity_logs(id uuid primary key default gen_random_uuid(),user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,activity_id bigint references public.activities(id) on delete set null,duration_minutes int not null check(duration_minutes>0),created_at timestamptz not null default now());
create table public.focus_sessions(id uuid primary key default gen_random_uuid(),user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,duration_minutes int not null check(duration_minutes>0),completed boolean not null default false,created_at timestamptz not null default now());
create table public.journal_entries(id uuid primary key default gen_random_uuid(),user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,mood text not null,content text not null check(char_length(content)<=800),created_at timestamptz not null default now());
create table public.tracks(id bigint generated by default as identity primary key,title text not null,kind text not null,minutes int not null,audio_path text,created_at timestamptz not null default now());
create table public.herbs(id bigint generated by default as identity primary key,name text not null,benefit text not null,use text not null,color text,created_at timestamptz not null default now());
create index activity_logs_user_created_idx on public.activity_logs(user_id,created_at desc);create index focus_sessions_user_created_idx on public.focus_sessions(user_id,created_at desc);create index journal_entries_user_created_idx on public.journal_entries(user_id,created_at desc);
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.user_roles where user_id=auth.uid() and role='admin')$$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,full_name) values(new.id,coalesce(new.raw_user_meta_data->>'full_name',''));insert into public.user_roles(user_id,role) values(new.id,'user');return new;end$$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
alter table public.profiles enable row level security;alter table public.user_roles enable row level security;alter table public.activities enable row level security;alter table public.activity_logs enable row level security;alter table public.focus_sessions enable row level security;alter table public.journal_entries enable row level security;alter table public.tracks enable row level security;alter table public.herbs enable row level security;
create policy "profiles readable by owner" on public.profiles for select using(id=auth.uid() or public.is_admin());create policy "profiles editable by owner" on public.profiles for update using(id=auth.uid());create policy "roles readable by owner" on public.user_roles for select using(user_id=auth.uid() or public.is_admin());
create policy "activities public read" on public.activities for select using(true);create policy "tracks public read" on public.tracks for select using(true);create policy "herbs public read" on public.herbs for select using(true);create policy "admins manage activities" on public.activities for all using(public.is_admin()) with check(public.is_admin());create policy "admins manage tracks" on public.tracks for all using(public.is_admin()) with check(public.is_admin());create policy "admins manage herbs" on public.herbs for all using(public.is_admin()) with check(public.is_admin());
create policy "users manage activity logs" on public.activity_logs for all using(user_id=auth.uid()) with check(user_id=auth.uid());create policy "users manage focus sessions" on public.focus_sessions for all using(user_id=auth.uid()) with check(user_id=auth.uid());create policy "users manage journal" on public.journal_entries for all using(user_id=auth.uid()) with check(user_id=auth.uid());
insert into storage.buckets(id,name,public) values('avatars','avatars',false),('wellness-audio','wellness-audio',true) on conflict(id) do nothing;
create policy "avatar owner upload" on storage.objects for insert to authenticated with check(bucket_id='avatars' and (storage.foldername(name))[1]=auth.uid()::text);create policy "avatar owner read" on storage.objects for select to authenticated using(bucket_id='avatars' and (storage.foldername(name))[1]=auth.uid()::text);create policy "public audio read" on storage.objects for select using(bucket_id='wellness-audio');create policy "admin audio manage" on storage.objects for all to authenticated using(bucket_id='wellness-audio' and public.is_admin()) with check(bucket_id='wellness-audio' and public.is_admin());
